import{D as e,S as t,b as n,f as r,g as i,h as a,j as o,k as s,r as c,t as l,u,x as d}from"./index-tRjMxKS7.js";var f={class:`content-main`},p={class:`content-wrapper`},m={class:`sidebar-container`},h={class:`sticky-toc`},g={class:`toc-list`},_=[`onClick`],v=l({__name:`PrivacyPolicyView`,setup(l){let v=c(),y=e(JSON.parse(localStorage.getItem(`user`)||`{}`)),b=e(`intro`),x=[{id:`intro`,label:`1. Introduction`},{id:`information-collect`,label:`2. Information We Collect`},{id:`purpose`,label:`3. Purpose of Collection`},{id:`data-sharing`,label:`4. Data Sharing and Disclosure`},{id:`data-security`,label:`5. Data Security`},{id:`data-retention`,label:`6. Data Retention`},{id:`your-rights`,label:`7. Your Rights`},{id:`contact`,label:`8. Contact Information`},{id:`updates`,label:`9. Updates to this Statement`}],S=e=>{b.value=e;let t=document.getElementById(e);if(t){let e=t.getBoundingClientRect().top+window.scrollY+-96;window.scrollTo({top:e,behavior:`smooth`})}};return n(()=>{(!y.value.id||y.value.role!==`gad_staff`)&&v.push(`/login`)}),(e,n)=>(d(),a(u,null,[r(`main`,f,[r(`div`,p,[r(`div`,m,[r(`div`,h,[n[0]||=r(`h3`,{class:`toc-title`},` Table of Contents `,-1),r(`ul`,g,[(d(),a(u,null,t(x,e=>r(`li`,{key:e.id},[r(`button`,{onClick:t=>S(e.id),class:s([`sidebar-nav-item`,{"active-nav-item":b.value===e.id}])},o(e.label),11,_)])),64))])])]),n[1]||=i(`<div class="content-area" data-v-f219a29d><div class="policy-card" data-v-f219a29d><div id="introduction" class="policy-section" data-v-f219a29d><div class="policy-header" data-v-f219a29d><div data-v-f219a29d><h1 class="policy-title" data-v-f219a29d>Data Privacy Statement</h1><p class="policy-subtitle" data-v-f219a29d> Benguet State University - Gender and Development Information Management System (GAD-IMS) </p></div></div></div><div id="intro" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>1. Introduction</h2><p class="section-text" data-v-f219a29d> Benguet State University (BSU) is committed to protecting the privacy and confidentiality of personal information collected, stored, and processed through the Gender and Development Information Management System (GAD-IMS). This Data Privacy Statement outlines our practices regarding the collection, use, and protection of your personal data in compliance with the Data Privacy Act of 2012 (Republic Act No. 10173). </p></div><div id="information-collect" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>2. Information We Collect</h2><p class="section-text" data-v-f219a29d> The GAD-IMS collects the following types of personal information: </p><ul class="styled-list" data-v-f219a29d><li data-v-f219a29d>Full name and contact information (<span class="highlight-text" data-v-f219a29d>email address, office/department</span>)</li><li data-v-f219a29d>Activity design and accomplishment report submissions</li><li data-v-f219a29d>Budget utilization data and financial information</li><li data-v-f219a29d>Attendance records and participant demographics (<span class="highlight-text" data-v-f219a29d>sex-disaggregated data</span>)</li><li data-v-f219a29d>User activity logs and system access records</li></ul></div><div id="purpose" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>3. Purpose of Collection</h2><p class="section-text" data-v-f219a29d> Your personal information is collected and processed for the following purposes: </p><ul class="styled-list" data-v-f219a29d><li data-v-f219a29d>Processing and evaluation of GAD activity designs and accomplishment reports</li><li data-v-f219a29d>Generation of GAD Plan and Budget (GPB) reports</li><li data-v-f219a29d>Monitoring and evaluation of GAD program implementation</li><li data-v-f219a29d>Compliance with government reporting requirements (<span class="highlight-text" data-v-f219a29d>PCW, CHED, DBM</span>)</li><li data-v-f219a29d>Research and statistical analysis for GAD program improvement</li></ul></div><div id="data-sharing" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>4. Data Sharing and Disclosure</h2><p class="section-text" data-v-f219a29d> BSU may share aggregated, anonymized data with government agencies such as the Philippine Commission on Women (PCW), Commission on Higher Education (CHED), and Department of Budget and Management (DBM) for reporting purposes. Personal information is not shared with third parties without your explicit consent, unless required by law. </p></div><div id="data-security" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>5. Data Security</h2><p class="section-text" data-v-f219a29d> BSU implements appropriate organizational, physical, and technical security measures to protect personal information from unauthorized access, alteration, disclosure, or destruction. These measures include access controls, encryption, regular security audits, and staff training on data protection. </p></div><div id="data-retention" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>6. Data Retention</h2><p class="section-text" data-v-f219a29d> Personal information is retained only for as long as necessary to fulfill the purposes for which it was collected, or as required by applicable laws and regulations. GAD records are typically retained for a period of ten (10) years in accordance with government archival requirements. </p></div><div id="your-rights" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>7. Your Rights</h2><p class="section-text" data-v-f219a29d> Under the Data Privacy Act, you have the right to: </p><ul class="styled-list" data-v-f219a29d><li data-v-f219a29d>Access your personal information</li><li data-v-f219a29d>Rectify inaccurate or incomplete data</li><li data-v-f219a29d>Request deletion or blocking of your data</li><li data-v-f219a29d>Object to the processing of your data</li><li data-v-f219a29d>Data portability</li></ul></div><div id="contact" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>8. Contact Information</h2><p class="section-text" data-v-f219a29d>For questions, concerns, or requests regarding your personal data, please contact:</p><div class="contact-box" data-v-f219a29d><p class="contact-title" data-v-f219a29d>Data Protection Officer</p><p class="contact-text" data-v-f219a29d>Benguet State University</p><p class="contact-text" data-v-f219a29d>La Trinidad, Benguet 2601</p><p class="contact-email" data-v-f219a29d>Email: dpo@bsu.edu.ph</p><p class="contact-text" data-v-f219a29d>Tel: (074) 422-2401</p></div></div><div id="updates" class="policy-section" data-v-f219a29d><h2 class="section-heading" data-v-f219a29d>9. Updates to this Statement</h2><p class="section-text" data-v-f219a29d> This Data Privacy Statement may be updated periodically. Users will be notified of significant changes through the system or via email. The effective date of the current version is displayed below. </p><p class="effective-date" data-v-f219a29d>Effective Date: January 1, 2026</p></div></div></div>`,1)])]),n[2]||=r(`footer`,{class:`footer-watermark`},[r(`p`,{class:`watermark-text`},` Benguet State University - Gender and Development Information Management System | GAD-IMS v1.0 `)],-1)],64))}},[[`__scopeId`,`data-v-f219a29d`]]);export{v as default};